---@class LRemoteResData
local LRemoteResData = LxClass("LRemoteResData", nil)

local downloadHandler = UnityEngine.Networking.DownloadHandler

LRemoteResData.NONE = 0
LRemoteResData.DOWNLOADING = 1
LRemoteResData.LOCAL = 2

function LRemoteResData:LRemoteResData()
    self._url = gLGameLogin:GetVideoResPath()
    self._saveUrl = CS.AppHelper.AppPersistentDataPath .. "remoteRes"
end


function LRemoteResData:Create(resName,endFunc)
    self._resName = resName
    self._endFunc = endFunc
    self._localFilePath = string.format("%s/%s",self._saveUrl,self._resName)
    self._remoteFilePath = string.format("%s%s",self._url,self._resName)

    self:StartInitData()
end

function LRemoteResData:StartInitData()

    local filePath = self._localFilePath

    if CS.FileExists(filePath) then
        self._state = LRemoteResData.LOCAL

        if self._endFunc then
            self._endFunc(self._localFilePath)
        end
        return
    else
        self:StartDownload()
    end
end

function LRemoteResData:StartDownload()
    if self._state == LRemoteResData.DOWNLOADING then
        return
    end

    self._state = LRemoteResData.DOWNLOADING

    local callback = function(url, ret, result, progress, bytes)

        if self._isDestroy then
            return
        end

        if ret == CS.YXWebRet.ok then
            if not CS.DirectoryExists(self._saveUrl) then
                CS.DirectoryCreate(self._saveUrl)
            end

            CS.FileWriteBytes(self._localFilePath,bytes)

            if self._endFunc then
                self._endFunc(self._localFilePath)
            end
        elseif ret == CS.YXWebRet.Loading then
            FireEvent(EventNames.REMOTE_DOWNLOAD_PROGRESS,self._resName,progress)
        else
            self:Destroy()
        end
    end

    if downloadHandler then
        local webRequest = LWebRequest:New()
        self._webRequest = webRequest
        webRequest:HttpDownFile(self._remoteFilePath,callback)
    else
        LxHttpHelper.DoWebDownFile({self._remoteFilePath},callback)
    end

end



function LRemoteResData:Destroy()
    if self._isDestroy then return end

    if self._webRequest then
        self._webRequest:Destroy()
    end

    self._webRequest = nil

    table.removeall(self)

    self._isDestroy = true
end


return LRemoteResData